import React from 'react';
import { motion } from 'framer-motion';
import { useSystem } from '../../context/SystemContext';

interface CyberButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger';
  glitch?: boolean;
}

const CyberButton: React.FC<CyberButtonProps> = ({ 
  children, 
  variant = 'primary', 
  glitch = true,
  className = '',
  ...props 
}) => {
  const { proMode } = useSystem();

  const baseStyles = "relative px-6 py-3 font-bold uppercase tracking-wider text-sm outline-none transition-all duration-200 overflow-hidden group";

  const variants = {
    primary: "bg-primary/10 border border-primary text-primary hover:bg-primary hover:text-black",
    secondary: "bg-transparent border border-gray-600 text-gray-400 hover:border-white hover:text-white",
    danger: "bg-red-500/10 border border-red-500 text-red-500 hover:bg-red-500 hover:text-white"
  };

  return (
    <motion.button
      whileHover={proMode ? {} : { scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      className={`${baseStyles} ${variants[variant]} ${className}`}
      {...props}
    >
      {!proMode && (
        <span className="absolute top-0 left-[-100%] w-full h-full bg-gradient-to-r from-transparent via-white/20 to-transparent skew-x-12 group-hover:animate-[shimmer_1s_infinite]" />
      )}
      <span className="relative z-10 flex items-center justify-center gap-2">
        {children}
      </span>
      {/* Corner decorations */}
      {!proMode && (
        <>
          <span className="absolute top-0 left-0 w-2 h-2 border-t border-l border-current opacity-50" />
          <span className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-current opacity-50" />
        </>
      )}
    </motion.button>
  );
};

export default CyberButton;

import React, { useEffect, useState } from 'react';
import { motion, useSpring, useMotionValue } from 'framer-motion';
import { useSystem } from '../../context/SystemContext';

const Cursor = () => {
  const { proMode, colors } = useSystem();
  const [clicked, setClicked] = useState(false);
  const [linkHovered, setLinkHovered] = useState(false);

  const cursorX = useMotionValue(-100);
  const cursorY = useMotionValue(-100);

  const springConfig = { damping: 25, stiffness: 400 };
  const cursorXSpring = useSpring(cursorX, springConfig);
  const cursorYSpring = useSpring(cursorY, springConfig);

  useEffect(() => {
    const moveCursor = (e: MouseEvent) => {
      cursorX.set(e.clientX - 16);
      cursorY.set(e.clientY - 16);
    };

    const handleMouseDown = () => setClicked(true);
    const handleMouseUp = () => setClicked(false);

    const handleLinkHoverStart = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.tagName.toLowerCase() === 'a' || target.tagName.toLowerCase() === 'button' || target.closest('button') || target.closest('a')) {
        setLinkHovered(true);
      }
    };

    const handleLinkHoverEnd = () => {
      setLinkHovered(false);
    };

    window.addEventListener('mousemove', moveCursor);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    // Use event delegation for hover detection
    document.addEventListener('mouseover', handleLinkHoverStart);
    document.addEventListener('mouseout', handleLinkHoverEnd);

    return () => {
      window.removeEventListener('mousemove', moveCursor);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      document.removeEventListener('mouseover', handleLinkHoverStart);
      document.removeEventListener('mouseout', handleLinkHoverEnd);
    };
  }, [cursorX, cursorY]);

  if (proMode) return null;

  return (
    <>
      <motion.div
        className="fixed top-0 left-0 w-8 h-8 border border-primary rounded-full pointer-events-none z-[9999] mix-blend-difference flex items-center justify-center"
        style={{
          x: cursorXSpring,
          y: cursorYSpring,
          borderColor: colors.primary
        }}
        animate={{
          scale: clicked ? 0.8 : linkHovered ? 1.5 : 1,
          rotate: linkHovered ? 45 : 0
        }}
      >
        <div className={`w-1 h-1 bg-current rounded-full ${linkHovered ? 'opacity-0' : 'opacity-100'}`} style={{ backgroundColor: colors.primary }} />
      </motion.div>
      {/* Trail effect */}
      <motion.div 
         className="fixed top-0 left-0 w-2 h-2 rounded-full pointer-events-none z-[9998] opacity-50"
         style={{
             x: cursorX,
             y: cursorY,
             backgroundColor: colors.secondary,
             translateX: 12,
             translateY: 12
         }}
         transition={{ duration: 0.1 }}
      />
    </>
  );
};

export default Cursor;

