              <h3 className="text-xl font-bold text-white mb-2 group-hover:text-primary transition-colors">{project.title}</h3>
              <p className="text-sm text-gray-400 line-clamp-2">{project.description}</p>
            </div>
          </motion.div>
        ))}
      </div>

