               initial={{ opacity: 0 }} 
               animate={{ opacity: 1 }} 
               exit={{ opacity: 0 }}
               onClick={() => setSelectedId(null)}
               className="absolute inset-0 bg-black/80 backdrop-blur-sm"
             />

             {/* Modal Content */}
             <motion.div 
               layoutId={selectedId}
               className="relative w-full max-w-4xl bg-gray-900 border border-gray-700 rounded-lg overflow-hidden shadow-2xl max-h-[90vh] overflow-y-auto"
               style={{ boxShadow: `0 0 30px ${colors.primary}20` }}
             >
                {(() => {
                  const project = PROJECTS.find(p => p.id === selectedId)!;
                  return (
                    <div className="flex flex-col">
                      {/* Hero Image in Modal */}
                      {project.image && (
                          <div className="w-full h-48 relative overflow-hidden group bg-black/50">
                              <img src={project.image} alt={project.title} className="w-full h-full object-cover opacity-80" />
                              <div className="absolute inset-0 bg-gradient-to-t from-gray-900 to-transparent" />
                          </div>
                      )}

                      <div className="flex flex-col md:flex-row">
                          {/* Left: Info */}
                          <div className="p-8 md:w-2/3">
                            <div className="flex justify-between items-start mb-6">
                                <div>
                                    <h2 className="text-3xl font-bold text-white">{project.title}</h2>
                                    <span className="text-primary font-mono text-sm">{project.category}</span>
                                </div>
