                <span className="text-gray-200">{PROFILE.location}</span>
             </div>
             <div className="flex justify-between items-center text-sm">
                <span className="text-gray-500 flex items-center gap-2"><Languages size={14}/> LING</span>
                <span className="text-gray-200">EN / FR / HT</span>
             </div>
             <div className="flex justify-between items-center text-sm">
                <span className="text-gray-500 flex items-center gap-2"><Shield size={14}/> STATUS</span>
                <span className="text-green-500 font-bold">ACTIVE</span>
             </div>
          </div>
        </div>

        {/* Mini Terminal */}
        <div className={`flex-1 min-h-[200px] flex flex-col rounded border p-4 font-mono text-xs ${proMode ? 'bg-white border-gray-200 text-black' : 'bg-black/50 border-gray-800 text-green-400'}`} style={{ borderColor: proMode ? '' : colors.primary }}>
          <div className="flex-1 overflow-y-auto space-y-2">
            {history.map((entry, i) => (
              <div key={i}>
                <div className="flex gap-2 opacity-60">
                  <span>$</span>
                  <span>{entry.cmd}</span>
                </div>
                <div className="mt-1 text-gray-300" style={{ color: proMode ? '#333' : '' }}>
                  {entry.output}
                </div>
              </div>
            ))}
