import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI, Type } from "@google/genai";
import { useSystem } from '../../context/SystemContext';
import { Radio, ShieldAlert, Cpu, Globe, Zap, Search, ExternalLink, Loader2, RefreshCw, Activity } from 'lucide-react';
import CyberButton from '../ui/CyberButton';

interface NewsItem {
  title: string;
  summary: string;
  source: string;
  url: string;
  category: string;
  timestamp: string;
}

const CATEGORIES = [
  { id: 'all', label: 'WIDE_BAND', icon: Globe },
  { id: 'ai', label: 'NEURAL_LINK', icon: Cpu },
  { id: 'security', label: 'NET_SEC', icon: ShieldAlert },
  { id: 'hardware', label: 'CORE_GEAR', icon: Zap },
  { id: 'culture', label: 'DIGITAL_C', icon: Radio },
];

const NewsModule = () => {
  const { colors, proMode } = useSystem();
  const [activeCat, setActiveCat] = useState('all');
  const [loading, setLoading] = useState(false);
  const [news, setNews] = useState<NewsItem[]>([]);
  const [error, setError] = useState<string | null>(null);

  const fetchIntel = async (category: string) => {
    setLoading(true);
    setError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Provide the 6 most recent and impactful technology news stories related to ${category === 'all' ? 'general technology, AI, and cybersecurity' : category} for today. 
      For each story, provide: 
      1. A short, punchy headline.
      2. A 2-sentence summary.
      3. The primary source name.
      4. A valid URL to the article.
      Return the data in a clear list format.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "";
      // Since response.text is markdown/text, and we want structured URLs,
      // we extract URLs from the grounding metadata if possible, or parse the text.
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = chunks.map(c => c.web?.uri).filter(Boolean);

      // We'll simulate a structured parse here for the demo, 
      // but in a production environment, we'd use responseSchema.
      // For now, let's format the AI output into cards.

      // Real-time generation of items based on the text
      const mockItems: NewsItem[] = text.split('\n\n').filter(t => t.length > 20).map((block, i) => {
        const lines = block.split('\n');
        return {
          title: lines[0]?.replace(/^#+\s*|\d+\.\s*/, '').trim() || "Intercepted Signal",
          summary: lines.slice(1).join(' ').substring(0, 160) + "...",
          source: "Global Intel Feed",
          url: sources[i] || "https://google.com/search?q=" + encodeURIComponent(lines[0]),
          category: category.toUpperCase(),
          timestamp: new Date().toLocaleTimeString(),
        };
      });

      setNews(mockItems.slice(0, 6));
    } catch (err) {
      console.error(err);
      setError("SIGNAL_LOST: Failed to decrypt news packets.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchIntel(activeCat);
  }, [activeCat]);

  return (
    <div className="h-full flex flex-col overflow-hidden bg-[radial-gradient(circle_at_center,rgba(var(--color-primary-rgb),0.05),transparent)]">
      {/* Header / Ticker */}
      <div className="bg-black/40 border-b border-gray-800 py-2 overflow-hidden flex items-center whitespace-nowrap">
        <div className="px-4 text-xs font-mono text-primary flex items-center gap-2 border-r border-gray-800 shrink-0">
          <Activity size={14} className="animate-pulse" /> LIVE_Intel
        </div>
        <motion.div 
          animate={{ x: [0, -1000] }}
          transition={{ duration: 30, repeat: Infinity, ease: "linear" }}
          className="flex gap-12 px-6"
        >
          {news.length > 0 ? news.map((n, i) => (
            <span key={i} className="text-[10px] font-mono text-gray-500 uppercase tracking-widest">
              [ {n.timestamp} ] {n.title} ••• 
            </span>
          )) : (
             <span className="text-[10px] font-mono text-gray-400">CONNECTING TO GLOBAL SIGNAL GRID... INITIALIZING GROUNDING TOOLS...</span>
          )}
        </motion.div>
      </div>

      <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
        {/* Navigation Sidebar */}
        <div className="w-full md:w-64 border-b md:border-b-0 md:border-r border-gray-800 p-4 space-y-2 shrink-0 bg-black/20">
          <h3 className="text-[10px] font-bold text-gray-500 uppercase tracking-[0.3em] mb-4 px-2">Bandwidth_Select</h3>
          {CATEGORIES.map((cat) => (
            <button
              key={cat.id}
