import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI } from "@google/genai";
import { useSystem } from '../../context/SystemContext';
import { Radio, ShieldAlert, Cpu, Globe, Zap, ExternalLink, Loader2, RefreshCw, Activity, Terminal as TerminalIcon, Satellite, Lock } from 'lucide-react';
import CyberButton from '../ui/CyberButton';

interface NewsItem {
  title: string;
  summary: string;
  source: string;
  url: string;
  category: string;
  timestamp: string;
  confidence: number;
}

const CATEGORIES = [
  { id: 'all', label: 'WIDE_BAND', icon: Globe },
  { id: 'ai', label: 'NEURAL_LINK', icon: Cpu },
  { id: 'security', label: 'NET_SEC', icon: ShieldAlert },
  { id: 'hardware', label: 'CORE_GEAR', icon: Zap },
  { id: 'culture', label: 'DIGITAL_C', icon: Radio },
];

const LOADING_STEPS = [
  "INITIALIZING UPLINK...",
  "BYPASSING ENCRYPTION...",
  "SYNCING SATELLITE HANDSHAKE...",
  "DECRYPTING PACKETS...",
  "VALIDATING SOURCE INTEGRITY...",
  "FINALIZING INTEL STREAM..."
];

const NewsModule = () => {
  const { colors, proMode } = useSystem();
  const [activeCat, setActiveCat] = useState('all');
  const [loading, setLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState(0);
  const [news, setNews] = useState<NewsItem[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Cycle loading messages
  useEffect(() => {
    let interval: number;
    if (loading) {
      interval = window.setInterval(() => {
        setLoadingStep((prev) => (prev + 1) % LOADING_STEPS.length);
      }, 800);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const fetchIntel = async (category: string) => {
    setLoading(true);
    setLoadingStep(0);
    setError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Provide exactly 6 highly impactful and current technology news stories for today related to ${category === 'all' ? 'AI, cybersecurity, emerging tech, and hardware' : category}.
      For each story, provide:
      1. Headline
      2. 2-sentence summary
      3. Source Name
      4. URL
      Keep the tone professional and slightly technical.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "";
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = chunks.map(c => c.web?.uri).filter(Boolean);

      // Extract items from AI text blocks
      const items: NewsItem[] = text.split('\n\n')
        .filter(t => t.length > 30)
        .map((block, i) => {
          const lines = block.split('\n');
          return {
            title: lines[0]?.replace(/^#+\s*|\d+\.\s*/, '').trim() || "Intercepted Signal",
            summary: lines.slice(1).join(' ').substring(0, 180).trim() + "...",
            source: "Global Intelligence",
            url: sources[i] || "https://google.com/search?q=" + encodeURIComponent(lines[0]),
            category: category.toUpperCase(),
            timestamp: new Date().toLocaleTimeString(),
            confidence: 85 + Math.floor(Math.random() * 14)
          };
        });

      setNews(items.slice(0, 6));
    } catch (err: any) {
      console.error(err);
      setError(err.message?.includes('entity was not found') 
        ? "SIGNAL_BLOCKED: Restricted Access or Invalid Protocol." 
        : "INTERCEPTION_FAILURE: Unable to establish clear signal.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchIntel(activeCat);
  }, [activeCat]);

  return (
    <div className="h-full flex flex-col overflow-hidden bg-black font-sans">
      {/* Ticker Tape Header */}
      <div className="bg-primary/5 border-b border-primary/20 py-2 overflow-hidden flex items-center whitespace-nowrap z-20">
        <div className="px-3 md:px-5 text-[10px] font-mono text-primary flex items-center gap-2 border-r border-primary/20 shrink-0 bg-black">
          <Activity size={12} className="animate-pulse" /> SYSTEM_STREAM
        </div>
        <motion.div 
          animate={{ x: [0, -1500] }}
          transition={{ duration: 40, repeat: Infinity, ease: "linear" }}
          className="flex gap-16 px-6"
        >
          {(news.length > 0 ? news : [{ title: "ESTABLISHING SECURE CONNECTION TO WORLDWIDE TECH GRID..." }]).map((n, i) => (
            <span key={i} className="text-[10px] font-mono text-gray-500 uppercase tracking-[0.2em]">
               SEC_LEVEL_4 // {n.title} // SIG_STRENGTH: 98%
            </span>
          ))}
        </motion.div>
      </div>

      <div className="flex-1 overflow-hidden flex flex-col md:flex-row relative">
        {/* Frequency Analyzer Decorative Background */}
