           <div className="w-10 h-10 border border-amber-500/50 rounded flex items-center justify-center">
              <BarChart3 size={20} className="text-amber-500" />
           </div>
           <div>
              <h1 className="text-xl font-bold tracking-tighter text-amber-500">QUANTUM LEDGER</h1>
              <p className="text-[10px] text-amber-700 tracking-widest">REAL-TIME MARKET ANALYTICS</p>
           </div>
        </div>
        <div className="hidden md:flex gap-4 text-xs text-amber-800">
           <div className="flex items-center gap-1"><Activity size={12}/> NASDAQ: LIVE</div>
           <div className="flex items-center gap-1"><Lock size={12}/> ENCRYPTED: AES-256</div>
        </div>
      </div>

      <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
         {/* Sector Navigation */}
         <div className="w-full md:w-48 border-b md:border-b-0 md:border-r border-amber-900/30 bg-amber-950/10 p-2 flex md:flex-col gap-1 overflow-x-auto md:overflow-visible no-scrollbar">
            {SECTORS.map(sec => (
               <button
                 key={sec.id}
                 onClick={() => setActiveSector(sec.id)}
                 disabled={loading}
                 className={`px-4 py-3 text-left text-xs font-bold uppercase transition-all border-l-2 shrink-0 ${
                   activeSector === sec.id 
                     ? 'border-amber-500 bg-amber-500/10 text-amber-400' 
                     : 'border-transparent text-amber-900 hover:text-amber-600 hover:bg-amber-900/10'
                 }`}
               >
                 {sec.label}
               </button>
            ))}
         </div>

         {/* Main Viewport */}
         <div className="flex-1 p-4 md:p-8 overflow-y-auto relative">

            {/* Background Grid */}
            <div 
              className="absolute inset-0 pointer-events-none opacity-10"
              style={{ backgroundImage: `linear-gradient(${THEME.grid} 1px, transparent 1px), linear-gradient(90deg, ${THEME.grid} 1px, transparent 1px)`, backgroundSize: '40px 40px' }}
            />

            <AnimatePresence mode="wait">
               {loading ? (
                  <motion.div 
                    key="loader"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="h-full flex flex-col items-center justify-center text-center space-y-8"
                  >
                     {/* Complex Loader Graphic */}
                     <div className="relative w-32 h-32">
                        {/* Rotating Rings */}
                        {[1, 2, 3].map((i) => (
                           <motion.div 
                             key={i}
                             className="absolute inset-0 border border-amber-500/30 rounded-full"
                             style={{ borderStyle: i % 2 === 0 ? 'dashed' : 'solid' }}
                             animate={{ rotate: i % 2 === 0 ? 360 : -360, scale: [1, 1.1, 1] }}
                             transition={{ duration: 3 + i, repeat: Infinity, ease: "linear" }}
                           />
                        ))}
                        <div className="absolute inset-0 flex items-center justify-center">
                           <DollarSign className="text-amber-500 animate-pulse" size={32} />
                        </div>
                     </div>

                     <div className="space-y-2">
                        <div className="text-amber-500 font-bold text-lg tracking-widest">{LOADING_PHASES[loadingPhase]}</div>
                        <div className="w-64 h-1 bg-amber-900/30 rounded-full overflow-hidden mx-auto">
                           <motion.div 
                             className="h-full bg-amber-500"
