                             animate={{ width: "100%" }}
                             transition={{ duration: 6, ease: "linear" }} // Approx total time
                           />
                        </div>
                     </div>
                  </motion.div>
               ) : error ? (
                  <motion.div 
                     key="error"
                     className="h-full flex flex-col items-center justify-center text-center"
                  >
                     <p className="text-red-500 font-bold mb-4">{error}</p>
                     <button 
