                     >
                       Retry Uplink
                     </button>
                  </motion.div>
               ) : (
                  <motion.div 
                    key="content"
                    className="grid grid-cols-1 lg:grid-cols-2 gap-6 relative z-10"
                    initial="hidden"
                    animate="visible"
                    variants={{
                      visible: { transition: { staggerChildren: 0.1 } }
                    }}
                  >
                     {stocks.map((stock, i) => (
                        <motion.div
                          key={stock.symbol}
                          variants={{
                             hidden: { opacity: 0, y: 20 },
                             visible: { opacity: 1, y: 0 }
                          }}
                          className="bg-amber-950/30 border border-amber-500/20 p-6 rounded hover:border-amber-500/60 transition-colors group relative overflow-hidden"
                        >
                           {/* Decorative Corner */}
                           <div className="absolute top-0 right-0 w-8 h-8 border-t-2 border-r-2 border-amber-500/20 group-hover:border-amber-500 transition-colors" />

                           <div className="flex justify-between items-start mb-4">
