                                 <h3 className="text-2xl font-black text-amber-500">{stock.symbol}</h3>
                                 <p className="text-xs text-amber-700 font-bold uppercase">{stock.name}</p>
                              </div>
                              <div className={`px-3 py-1 rounded text-xs font-bold border ${
                                 stock.sentiment === 'BUY' ? 'border-green-500/50 text-green-500 bg-green-500/10' :
                                 stock.sentiment === 'SELL' ? 'border-red-500/50 text-red-500 bg-red-500/10' :
                                 'border-amber-500/50 text-amber-500 bg-amber-500/10'
                              }`}>
                                 {stock.sentiment}
                              </div>
                           </div>

                           <div className="flex justify-between items-end mb-6">
                              <div className="text-4xl font-bold text-white tracking-tighter">{stock.price}</div>
                              <div className={`text-sm font-bold flex items-center gap-1 ${stock.change.includes('+') ? 'text-green-500' : 'text-red-500'}`}>
