                 <h4 className="text-primary font-bold text-sm">ACHIEVEMENT UNLOCKED</h4>
                 <p className="text-white font-bold">{recentAchievement.title}</p>
                 <p className="text-gray-400 text-xs">{recentAchievement.description}</p>
              </div>
           </MotionDiv>
