             <div className="p-4 text-center text-gray-500 text-sm">No commands found.</div>
          )}
        </div>
        <div className="bg-gray-950 p-2 border-t border-gray-800 text-[10px] text-gray-500 flex justify-end gap-4 px-4">
           <span>Select ↵</span>
           <span>Navigate ↑↓</span>
           <span>Close ESC</span>
        </div>
      </MotionDiv>
    </div>
  );
};

