  { id: 'all', label: 'GLOBAL_FEED', icon: Globe, color: 'text-blue-400', border: 'border-blue-400' },
  { id: 'ai', label: 'NEURAL_NET', icon: Cpu, color: 'text-purple-400', border: 'border-purple-400' },
